content.content:
     1→/* ============ Notes Section ============ */
     2→.profile-notes-section {
     3→    width: 100%;
     4→    padding: 1rem 0;
     5→    display: flex;
     6→    flex-direction: column;
     7→    gap: 1rem;
     8→}
     9→
    10→.notes-actions {
    11→    display: flex;
    12→    gap: 0.5rem;
    13→    width: 100%;
    14→}
    15→
    16→.add-note-button {
    17→    flex: 1;
    18→    padding: 0.75rem 1rem;
    19→    background: var(--bg-glass);
    20→    backdrop-filter: blur(25px);
    21→    -webkit-backdrop-filter: blur(25px);
    22→    border: 1px dashed var(--text-muted);
    23→    border-radius: 12px;
    24→    color: var(--text-secondary);
    25→    font-family: "Lexend Deca", sans-serif;
    26→    font-size: 0.875rem;
    27→    font-weight: 500;
    28→    cursor: pointer;
    29→    transition: all 0.2s ease;
    30→    display: flex;
    31→    align-items: center;
    32→    justify-content: center;
    33→    gap: 0.5rem;
    34→}
    35→
    36→.add-note-button:hover {
    37→    background: var(--bg-elevated);
    38→    border-color: var(--text-secondary);
    39→    transform: translateY(-1px);
    40→}
    41→
    42→.add-note-button:disabled {
    43→    opacity: 0.4;
    44→    cursor: not-allowed;
    45→    transform: none;
    46→}
    47→
    48→.notes-list {
    49→    display: flex;
    50→    flex-direction: column;
    51→    gap: 1rem;
    52→}
    53→
    54→/* ============ Note Container ============ */
    55→.profile-note-container {
    56→    position: relative;
    57→    padding: 1rem;
    58→    backdrop-filter: blur(15px);
    59→    -webkit-backdrop-filter: blur(15px);
    60→    transition: box-shadow 0.3s ease;
    61→    height: auto;
    62→    z-index: 0;
    63→}
    64→
    65→.profile-note-container:hover {
    66→    z-index: 5;
    67→}
    68→
    69→.profile-note-container:hover {
    70→    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
    71→}
    72→
    73→.note-controls {
    74→    position: absolute;
    75→    top: 0.5rem;
    76→    right: 0.5rem;
    77→    display: flex;
    78→    gap: 0.35rem;
    79→    opacity: 0;
    80→    transition: opacity 0.2s ease;
    81→    z-index: 5;
    82→}
    83→
    84→.profile-note-container:hover .note-controls {
    85→    opacity: 1;
    86→}
    87→
    88→.note-control-btn {
    89→    padding: 0.35rem;
    90→    background: var(--bg-glass);
    91→    backdrop-filter: blur(10px);
    92→    -webkit-backdrop-filter: blur(10px);
    93→    border: 1px solid rgba(255, 255, 255, 0.2);
    94→    border-radius: 6px;
    95→    color: var(--text-secondary);
    96→    cursor: pointer;
    97→    display: flex;
    98→    align-items: center;
    99→    justify-content: center;
   100→    transition: all 0.2s ease;
   101→}
   102→
   103→.note-control-btn:hover {
   104→    background: var(--bg-elevated);
   105→    color: var(--text-primary);
   106→}
   107→
   108→.note-control-btn.delete-btn:hover {
   109→    background: rgba(244, 67, 54, 0.15);
   110→    color: #f44336;
   111→    border-color: rgba(244, 67, 54, 0.3);
   112→}
   113→
   114→/* ============ Inline Note Editor ============ */
   115→.inline-note-editor-wrapper {
   116→    width: 100%;
   117→}
   118→
   119→.inline-note-toolbar {
   120→    display: flex;
   121→    gap: 0.25rem;
   122→    padding: 0.35rem 0.5rem;
   123→    background: var(--bg-glass);
   124→    backdrop-filter: blur(15px);
   125→    -webkit-backdrop-filter: blur(15px);
   126→    border-radius: 8px;
   127→    margin-bottom: 0.5rem;
   128→    flex-wrap: wrap;
   129→    align-items: center;
   130→    border: 1px solid rgba(255, 255, 255, 0.1);
   131→}
   132→
   133→.inline-toolbar-btn {
   134→    padding: 0.25rem 0.35rem;
   135→    background: transparent;
   136→    border: 1px solid transparent;
   137→    border-radius: 4px;
   138→    cursor: pointer;
   139→    transition: all 0.15s ease;
   140→    display: flex;
   141→    align-items: center;
   142→    justify-content: center;
   143→    color: inherit;
   144→}
   145→
   146→.inline-toolbar-btn:hover {
   147→    background: rgba(255, 255, 255, 0.15);
   148→    border-color: rgba(255, 255, 255, 0.1);
   149→}
   150→
   151→.inline-toolbar-btn.is-active {
   152→    background: var(--accent-purple);
   153→    color: white;
   154→    border-color: var(--accent-purple);
   155→}
   156→
   157→.inline-toolbar-divider {
   158→    width: 1px;
   159→    height: 20px;
   160→    background: rgba(255, 255, 255, 0.15);
   161→    margin: 0 0.2rem;
   162→}
   163→
   164→.inline-note-content-editable {
   165→    min-height: 0;
   166→    max-height: none;
   167→    overflow: visible;
   168→    outline: none;
   169→    font-size: 0.9rem;
   170→    line-height: 1.6;
   171→    padding: 0.25rem;
   172→}
   173→
   174→.inline-note-content-editable-container {
   175→    position: relative;
   176→}
   177→
   178→.inline-note-content-editable.with-inline-save {
   179→    padding-bottom: 2.5rem;
   180→}
   181→
   182→.inline-note-inline-save-btn {
   183→    position: absolute;
   184→    right: 0.5rem;
   185→    bottom: 0.5rem;
   186→    padding: 0.35rem 0.6rem;
   187→    background: var(--accent-purple);
   188→    border: 1px solid var(--accent-purple);
   189→    border-radius: 8px;
   190→    color: white;
   191→    font-family: "Lexend Deca", sans-serif;
   192→    font-size: 0.72rem;
   193→    font-weight: 600;
   194→    cursor: pointer;
   195→    transition: opacity 0.15s ease;
   196→    z-index: 2;
   197→}
   198→
   199→.inline-note-inline-save-btn:hover {
   200→    opacity: 0.9;
   201→}
   202→
   203→.inline-note-inline-save-btn:disabled {
   204→    opacity: 0.55;
   205→    cursor: not-allowed;
   206→}
   207→
   208→.inline-note-add-container-btn {
   209→    position: absolute;
   210→    left: 0.5rem;
   211→    bottom: 0.5rem;
   212→    padding: 0.35rem 0.6rem;
   213→    background: rgba(37, 99, 235, 0.1);
   214→    border: 1px solid #2563eb;
   215→    border-radius: 8px;
   216→    color: #2563eb;
   217→    font-family: "Lexend Deca", sans-serif;
   218→    font-size: 0.72rem;
   219→    font-weight: 600;
   220→    cursor: pointer;
   221→    transition: opacity 0.15s ease, background 0.15s ease;
   222→    z-index: 2;
   223→}
   224→
   225→.inline-note-add-container-btn:hover {
   226→    background: rgba(37, 99, 235, 0.18);
   227→}
   228→
   229→.inline-note-content-editable:focus {
   230→    outline: none;
   231→}
   232→
   233→.inline-note-placeholder {
   234→    color: var(--text-muted);
   235→    font-size: 0.9rem;
   236→    position: absolute;
   237→    top: 0.25rem;
   238→    left: 0.25rem;
   239→    pointer-events: none;
   240→    opacity: 0.6;
   241→}
   242→
   243→.inline-note-editor-shell {
   244→    position: relative;
   245→}
   246→
   247→/* ============ Read Only Note ============ */
   248→.readonly-note-content {
   249→    font-size: 0.9rem;
   250→    line-height: 1.6;
   251→    min-height: 30px;
   252→}
   253→
   254→body.visit-note-fullview-active {
   255→    overflow: hidden;
   256→}
   257→
   258→.readonly-note-content.visit-inner-expand-enabled .note-inner-container {
   259→    cursor: zoom-in;
   260→}
   261→
   262→.readonly-note-content.visit-inner-expand-enabled .note-inner-container.is-visit-full-view {
   263→    position: fixed !important;
   264→    inset: 5vh 5vw !important;
   265→    width: auto !important;
   266→    max-width: none !important;
   267→    max-height: 90vh !important;
   268→    margin: 0 !important;
   269→    transform: none !important;
   270→    overflow: auto !important;
   271→    cursor: zoom-out;
   272→    z-index: 1200 !important;
   273→    box-shadow: 0 20px 64px rgba(0, 0, 0, 0.35), 0 0 0 100vmax rgba(0, 0, 0, 0.45);
   274→}
   275→
   276→.readonly-note-placeholder {
   277→    color: var(--text-muted);
   278→    font-size: 0.875rem;
   279→    font-style: italic;
   280→}
   281→
   282→/* ============ Note Style Editor ============ */
   283→.note-style-editor-overlay {
   284→    position: fixed;
   285→    inset: 0;
   286→    background: rgba(0, 0, 0, 0.4);
   287→    backdrop-filter: blur(4px);
   288→    -webkit-backdrop-filter: blur(4px);
   289→    z-index: 100;
   290→    display: flex;
   291→    align-items: center;
   292→    justify-content: center;
   293→}
   294→
   295→.note-style-editor {
   296→    background: var(--bg-primary);
   297→    border-radius: 16px;
   298→    padding: 1.5rem;
   299→    width: 340px;
   300→    max-height: 80vh;
   301→    overflow-y: auto;
   302→    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.25);
   303→    display: flex;
   304→    flex-direction: column;
   305→    gap: 1rem;
   306→}
   307→
   308→.note-style-editor h3 {
   309→    margin: 0;
   310→    font-size: 1rem;
   311→    font-weight: 600;
   312→    color: var(--text-primary);
   313→    font-family: "Lexend Deca", sans-serif;
   314→}
   315→
   316→.style-field {
   317→    display: flex;
   318→    flex-direction: column;
   319→    gap: 0.35rem;
   320→}
   321→
   322→.style-field label {
   323→    font-size: 0.75rem;
   324→    font-weight: 500;
   325→    color: var(--text-secondary);
   326→    text-transform: uppercase;
   327→    letter-spacing: 0.5px;
   328→}
   329→
   330→.style-field-row {
   331→    display: flex;
   332→    align-items: center;
   333→    gap: 0.5rem;
   334→}
   335→
   336→.style-color-preview {
   337→    width: 32px;
   338→    height: 32px;
   339→    border-radius: 6px;
   340→    border: 2px solid var(--text-muted);
   341→    cursor: pointer;
   342→    flex-shrink: 0;
   343→}
   344→
   345→.style-color-input {
   346→    position: absolute;
   347→    opacity: 0;
   348→    width: 0;
   349→    height: 0;
   350→    pointer-events: none;
   351→}
   352→
   353→.style-range-input {
   354→    flex: 1;
   355→    accent-color: var(--accent-purple);
   356→    height: 4px;
   357→}
   358→
   359→.style-range-value {
   360→    font-size: 0.75rem;
   361→    color: var(--text-muted);
   362→    min-width: 32px;
   363→    text-align: right;
   364→}
   365→
   366→.style-select {
   367→    flex: 1;
   368→    padding: 0.4rem 0.6rem;
   369→    border: 1px solid var(--text-muted);
   370→    border-radius: 6px;
   371→    background: var(--bg-secondary);
   372→    color: var(--text-primary);
   373→    font-size: 0.8rem;
   374→    font-family: "Lexend Deca", sans-serif;
   375→    outline: none;
   376→}
   377→
   378→.style-select:focus {
   379→    border-color: var(--accent-purple);
   380→}
   381→
   382→.note-style-actions {
   383→    display: flex;
   384→    gap: 0.5rem;
   385→    margin-top: 0.5rem;
   386→}
   387→
   388→.note-style-cancel-btn {
   389→    flex: 1;
   390→    padding: 0.5rem;
   391→    background: transparent;
   392→    border: 1px solid var(--text-muted);
   393→    border-radius: 8px;
   394→    color: var(--text-secondary);
   395→    font-family: "Lexend Deca", sans-serif;
   396→    font-size: 0.8rem;
   397→    cursor: pointer;
   398→    transition: all 0.2s;
   399→}
   400→
   401→.note-style-cancel-btn:hover {
   402→    background: var(--bg-secondary);
   403→}
   404→
   405→.note-style-save-btn {
   406→    flex: 1;
   407→    padding: 0.5rem;
   408→    background: var(--accent-purple);
   409→    border: none;
   410→    border-radius: 8px;
   411→    color: white;
   412→    font-family: "Lexend Deca", sans-serif;
   413→    font-size: 0.8rem;
   414→    font-weight: 500;
   415→    cursor: pointer;
   416→    transition: all 0.2s;
   417→}
   418→
   419→.note-style-save-btn:hover {
   420→    opacity: 0.9;
   421→}
   422→
   423→/* ============ Note style preview ============ */
   424→.style-preview-box {
   425→    padding: 0.75rem;
   426→    border-radius: 8px;
   427→    font-size: 0.8rem;
   428→    text-align: center;
   429→    color: var(--text-secondary);
   430→}
   431→
   432→/* ============ Note saving indicator ============ */
   433→.notes-saving-indicator {
   434→    display: flex;
   435→    align-items: center;
   436→    justify-content: center;
   437→    padding: 0.25rem;
   438→    font-size: 0.7rem;
   439→    color: var(--text-muted);
   440→    gap: 0.35rem;
   441→}
   442→
   443→/* ============ Container Node (Inner Containers) ============ */
   444→.container-node-wrapper {
   445→    margin: 0.4rem 0;
   446→}
   447→
   448→.note-inner-container {
   449→    position: relative;
   450→    box-sizing: border-box;
   451→    max-width: 100%;
   452→    padding: 0.5rem 0.75rem;
   453→    margin: 0.4rem 0;
   454→    min-height: 28px;
   455→    transition: all 0.15s ease;
   456→    word-wrap: break-word;
   457→    overflow-wrap: break-word;
   458→    z-index: 0;
   459→}
   460→
   461→.note-inner-container:hover {
   462→    z-index: 5;
   463→}
   464→
   465→.note-inner-container.is-dragging {
   466→    z-index: 8;
   467→    user-select: none;
   468→}
   469→
   470→.note-inner-container:hover > .inner-container-controls {
   471→    opacity: 1;
   472→}
   473→
   474→.inner-container-controls {
   475→    position: absolute;
   476→    top: 4px;
   477→    right: 4px;
   478→    display: flex;
   479→    justify-content: flex-end;
   480→    flex-wrap: wrap;
   481→    max-width: calc(100% - 8px);
   482→    gap: 2px;
   483→    opacity: 0;
   484→    transition: opacity 0.15s ease;
   485→    z-index: 4;
   486→}
   487→
   488→.inner-container-control-btn {
   489→    width: 22px;
   490→    height: 22px;
   491→    display: flex;
   492→    align-items: center;
   493→    justify-content: center;
   494→    background: rgba(255, 255, 255, 0.75);
   495→    backdrop-filter: blur(8px);
   496→    -webkit-backdrop-filter: blur(8px);
   497→    border: 1px solid rgba(0, 0, 0, 0.1);
   498→    border-radius: 4px;
   499→    cursor: pointer;
   500→    color: var(--text-secondary);
   501→    transition: all 0.15s ease;
   502→    padding: 0;
   503→}
   504→
   505→.inner-container-control-btn:hover {
   506→    background: rgba(255, 255, 255, 0.95);
   507→    color: var(--text-primary);
   508→    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
   509→}
   510→
   511→.inner-container-control-btn.is-active {
   512→    background: var(--accent-purple);
   513→    color: #ffffff;
   514→    border-color: var(--accent-purple);
   515→}
   516→
   517→.inner-container-drag-btn {
   518→    cursor: grab;
   519→}
   520→
   521→.note-inner-container.is-dragging .inner-container-drag-btn {
   522→    cursor: grabbing;
   523→}
   524→
   525→/* Inner container style popup */
   526→.inner-container-style-popup {
   527→    position: absolute;
   528→    top: 50%;
   529→    left: 50%;
   530→    transform: translate(-50%, -50%);
   531→    z-index: 10;
   532→    background: var(--bg-primary);
   533→    border: 1px solid var(--border-light);
   534→    border-radius: 10px;
   535→    padding: 0.6rem;
   536→    min-width: 180px;
   537→    box-shadow: 0 6px 20px rgba(0, 0, 0, 0.15);
   538→    display: flex;
   539→    flex-direction: column;
   540→    gap: 0.4rem;
   541→}
   542→
   543→.icsp-row {
   544→    display: flex;
   545→    align-items: center;
   546→    gap: 0.4rem;
   547→    font-size: 0.7rem;
   548→    color: var(--text-secondary);
   549→}
   550→
   551→.icsp-row label {
   552→    min-width: 42px;
   553→    font-weight: 600;
   554→    font-size: 0.65rem;
   555→    text-transform: uppercase;
   556→    letter-spacing: 0.3px;
   557→    color: var(--text-muted);
   558→    flex-shrink: 0;
   559→}
   560→
   561→.icsp-row input[type="color"] {
   562→    width: 24px;
   563→    height: 24px;
   564→    border: 1px solid var(--border-light);
   565→    border-radius: 4px;
   566→    padding: 1px;
   567→    cursor: pointer;
   568→    background: none;
   569→}
   570→
   571→.icsp-row input[type="range"] {
   572→    flex: 1;
   573→    height: 4px;
   574→    accent-color: var(--accent-purple);
   575→    cursor: pointer;
   576→}
   577→
   578→.icsp-row select {
   579→    flex: 1;
   580→    padding: 0.2rem 0.35rem;
   581→    font-size: 0.7rem;
   582→    border: 1px solid var(--border-light);
   583→    border-radius: 4px;
   584→    background: var(--bg-secondary);
   585→    color: var(--text-primary);
   586→    font-family: "Lexend Deca", sans-serif;
   587→    outline: none;
   588→    cursor: pointer;
   589→}
   590→
   591→.icsp-row select:focus {
   592→    border-color: var(--accent-purple);
   593→}
   594→
   595→.icsp-close {
   596→    margin-top: 0.2rem;
   597→    padding: 0.3rem 0.5rem;
   598→    background: var(--accent-purple);
   599→    color: white;
   600→    border: none;
   601→    border-radius: 6px;
   602→    font-size: 0.7rem;
   603→    font-family: "Lexend Deca", sans-serif;
   604→    font-weight: 500;
   605→    cursor: pointer;
   606→    transition: opacity 0.15s ease;
   607→}
   608→
   609→.icsp-close:hover {
   610→    opacity: 0.85;
   611→}
   612→
   613→/* Inner container text editing */
   614→.inner-container-text-input {
   615→    width: 100%;
   616→    background: transparent;
   617→    border: none;
   618→    outline: none;
   619→    font-family: inherit;
   620→    color: inherit;
   621→    padding: 0;
   622→    margin: 0;
   623→    line-height: 1.4;
   624→    min-height: 100%;
   625→    resize: none;
   626→    white-space: pre-wrap;
   627→    overflow: hidden;
   628→    overflow-wrap: anywhere;
   629→    word-break: break-word;
   630→    box-sizing: border-box;
   631→    display: block;
   632→}
   633→
   634→.inner-container-text-input::placeholder {
   635→    color: inherit;
   636→    opacity: 0.4;
   637→}
   638→
   639→.inner-container-text-display {
   640→    cursor: text;
   641→    min-height: 1em;
   642→    line-height: 1.4;
   643→    white-space: pre-wrap;
   644→    word-break: break-word;
   645→}
   646→
   647→/* Inner container delete button */
   648→.inner-container-delete-btn:hover {
   649→    background: rgba(244, 67, 54, 0.12) !important;
   650→    color: #f44336 !important;
   651→    border-color: rgba(244, 67, 54, 0.25) !important;
   652→}
   653→
   654→/* Inner container image */
   655→.inner-container-img-wrap {
   656→    position: relative;
   657→    margin-bottom: 0.35rem;
   658→    line-height: 0;
   659→    min-width: 80px;
   660→    min-height: 80px;
   661→}
   662→
   663→.inner-container-img {
   664→    width: 100%;
   665→    height: 100%;
   666→    border-radius: inherit;
   667→    object-fit: fill;
   668→    display: block;
   669→    transition: opacity 0.2s ease;
   670→}
   671→
   672→.inner-container-img.loading {
   673→    opacity: 0.5;
   674→}
   675→
   676→.inner-container-img.draggable {
   677→    cursor: grab;
   678→    user-select: none;
   679→}
   680→
   681→.inner-container-img-wrap.dragging .inner-container-img.draggable {
   682→    cursor: grabbing;
   683→}
   684→
   685→.inner-container-img-remove {
   686→    position: absolute;
   687→    top: 4px;
   688→    right: 4px;
   689→    width: 20px;
   690→    height: 20px;
   691→    display: flex;
   692→    align-items: center;
   693→    justify-content: center;
   694→    background: rgba(0, 0, 0, 0.55);
   695→    border: none;
   696→    border-radius: 50%;
