     1→import React, { useState } from "react";
     2→import { AnimatePresence } from "framer-motion";
     3→import InlineNoteEditor from "./InlineNoteEditor";
     4→import ReadOnlyNoteView from "./ReadOnlyNoteView";
     5→import NoteStyleEditor from "./NoteStyleEditor";
     6→
     7→const NoteContainer = ({
     8→    note,
     9→    isOwner,
    10→    expandInnerContainerOnClick,
    11→    onUpdateContent,
    12→    onUpdateStyle,
    13→    onDelete,
    14→    onSaveNotes,
    15→    hasUnsavedChanges,
    16→    isSaving,
    17→}) => {
    18→    const [showStyleEditor, setShowStyleEditor] = useState(false);
    19→
    20→    const containerStyles = {
    21→        backgroundColor: note.containerStyle?.bgColor || "rgba(255,255,255,0.15)",
    22→        borderColor: note.containerStyle?.borderColor || "#888888",
    23→        borderWidth: `${note.containerStyle?.borderWidth ?? 1}px`,
    24→        borderStyle: note.containerStyle?.borderStyle || "solid",
    25→        borderRadius: `${note.containerStyle?.borderRadius ?? 8}px`,
    26→        color: note.fontColor || "#000000",
    27→        fontFamily: note.fontFamily === "inherit" ? undefined : note.fontFamily,
    28→    };
    29→
    30→    const handleSaveStyle = (styleData) => {
    31→        onUpdateStyle(styleData);
    32→        setShowStyleEditor(false);
    33→    };
    34→
    35→    return (
    36→        <>
    37→            <div className="profile-note-container" style={containerStyles}>
    38→                {isOwner && (
    39→                    <div className="note-controls">
    40→                        <button
    41→                            className="note-control-btn"
    42→                            onClick={() => setShowStyleEditor(true)}
    43→                            title="Edit style"
    44→                        >
    45→                            <svg xmlns="http://www.w3.org/2000/svg" height="16px" viewBox="0 -960 960 960" width="16px" fill="currentColor">
    46→                                <path d="M480-400q-33 0-56.5-23.5T400-480q0-33 23.5-56.5T480-560q33 0 56.5 23.5T560-480q0 33-23.5 56.5T480-400ZM320-240h320v-23q0-24-13-44t-36-30q-26-11-53.5-17t-57.5-6q-30 0-57.5 6T369-337q-23 10-36 30t-13 44v23ZM720-80H240q-33 0-56.5-23.5T160-160v-640q0-33 23.5-56.5T240-880h320l240 240v480q0 33-23.5 56.5T720-80Z" />
    47→                            </svg>
    48→                        </button>
    49→                        <button
    50→                            type="button"
    51→                            className="note-control-btn delete-btn"
    52→                            onClick={(e) => {
    53→                                e.stopPropagation();
    54→                                onDelete();
    55→                            }}
    56→                            title="Delete note"
    57→                        >
    58→                            <svg xmlns="http://www.w3.org/2000/svg" height="16px" viewBox="0 -960 960 960" width="16px" fill="currentColor">
    59→                                <path d="M280-120q-33 0-56.5-23.5T200-200v-520h-40v-80h200v-40h240v40h200v80h-40v520q0 33-23.5 56.5T680-120H280Zm400-600H280v520h400v-520ZM360-280h80v-360h-80v360Zm160 0h80v-360h-80v360ZM280-720v520-520Z" />
    60→                            </svg>
    61→                        </button>
    62→                    </div>
    63→                )}
    64→
    65→                {isOwner ? (
    66→                    <InlineNoteEditor
    67→                        initialContent={note.content}
    68→                        onSave={onUpdateContent}
    69→                        onExplicitSave={onSaveNotes}
    70→                        hasUnsavedChanges={hasUnsavedChanges}
    71→                        isSaving={isSaving}
    72→                    />
    73→                ) : (
    74→                    <ReadOnlyNoteView
    75→                        content={note.content}
    76→                        expandInnerContainerOnClick={expandInnerContainerOnClick}
    77→                    />
    78→                )}
    79→            </div>
    80→
    81→            <AnimatePresence>
    82→                {showStyleEditor && (
    83→                    <NoteStyleEditor
    84→                        containerStyle={note.containerStyle}
    85→                        fontColor={note.fontColor}
    86→                        fontFamily={note.fontFamily}
    87→                        onSave={handleSaveStyle}
    88→                        onClose={() => setShowStyleEditor(false)}
    89→                    />
    90→                )}
    91→            </AnimatePresence>
    92→        </>
    93→    );
    94→};
    95→
    96→export default NoteContainer;
    97→

