    42→};
    43→
    44→const ReadOnlyNoteView = ({ content, expandInnerContainerOnClick = false }) => {
    45→    const contentEditableRef = useRef(null);
    46→
    47→    const initialConfig = {
    48→        namespace: "ReadOnlyNote",
    49→        editable: false,
    50→        nodes: [ImageNode, HeadingNode, QuoteNode, ContainerNode],
    51→        theme,
    52→        onError: (error) => console.error("ReadOnlyNote error:", error),
    53→    };
    54→
    55→    const collapseExpandedInnerContainers = useCallback(() => {
    56→        document
    57→            .querySelectorAll(".note-inner-container.is-visit-full-view")
    58→            .forEach((element) => element.classList.remove("is-visit-full-view"));
    59→        document.body.classList.remove("visit-note-fullview-active");
    60→    }, []);
    61→
    62→    const handleInnerContainerClick = useCallback(
    63→        (event) => {
    64→            if (!expandInnerContainerOnClick) return;
    65→
    66→            const rawTarget = event.target;
    67→            const targetElement =
    68→                rawTarget instanceof Element ? rawTarget : rawTarget?.parentElement || null;
    69→            if (!targetElement) return;
    70→
    71→            const targetContainer = targetElement.closest(".note-inner-container");
    72→            if (!targetContainer) return;
    73→
    74→            const shouldExpand = !targetContainer.classList.contains("is-visit-full-view");
    75→            collapseExpandedInnerContainers();
    76→
    77→            if (shouldExpand) {
    78→                targetContainer.classList.add("is-visit-full-view");
    79→                document.body.classList.add("visit-note-fullview-active");
    80→            }
    81→        },
    82→        [collapseExpandedInnerContainers, expandInnerContainerOnClick]
    83→    );
    84→
    85→    useEffect(() => {
    86→        if (!expandInnerContainerOnClick || !contentEditableRef.current) return undefined;
    87→
    88→        const rootEl = contentEditableRef.current;
    89→        const handleRootClick = (event) => handleInnerContainerClick(event);
    90→
    91→        rootEl.addEventListener("click", handleRootClick);
    92→        return () => {
    93→            rootEl.removeEventListener("click", handleRootClick);
    94→        };
    95→    }, [expandInnerContainerOnClick, handleInnerContainerClick]);
    96→
    97→    useEffect(() => {
    98→        if (!expandInnerContainerOnClick) return undefined;
    99→
   100→        const handleKeyDown = (event) => {
   101→            if (event.key === "Escape") {
   102→                collapseExpandedInnerContainers();
   103→            }
   104→        };
   105→
   106→        document.addEventListener("keydown", handleKeyDown);
   107→        return () => {
   108→            document.removeEventListener("keydown", handleKeyDown);
   109→            collapseExpandedInnerContainers();
   110→        };
   111→    }, [collapseExpandedInnerContainers, expandInnerContainerOnClick]);
   112→
   113→    if (!content) {
   114→        return <div className="readonly-note-placeholder">Empty note</div>;
   115→    }
   116→
   117→    return (
   118→        <LexicalComposer initialConfig={initialConfig}>
   119→            <RichTextPlugin
   120→                contentEditable={
   121→                    <ContentEditable
   122→                        ref={contentEditableRef}
   123→                        className={`readonly-note-content${expandInnerContainerOnClick ? " visit-inner-expand-enabled" : ""}`}
   124→                    />
   125→                }
   126→                placeholder={null}
   127→                ErrorBoundary={LexicalErrorBoundary}
   128→            />
   129→            <LoadContentPlugin content={content} />
   130→        </LexicalComposer>
   131→    );
   132→};
   133→
   134→export default ReadOnlyNoteView;
   135→

